// Normalize Alertmanager payload into a chat-like message
const alerts = $input.item.json.body?.alerts || [];
const firing = alerts.filter(a => a.status === 'firing');

if (firing.length === 0) {
  return [{ json: { skip: true } }];
}

const lines = firing.map(a => {
  const labels = a.labels || {};
  const annotations = a.annotations || {};
  return `â€˘ [${labels.severity?.toUpperCase() || 'ALERT'}] ${labels.alertname} on ${labels.instance || labels.job || 'unknown'}: ${annotations.summary || annotations.description || 'no description'}`;
});

return [{
  json: {
    chatInput: `Alertmanager fired the following alerts. Investigate and propose remediation:\n${lines.join('\n')}`,
    source: 'alertmanager'
  }
}];

return [{
  json: {
    chatInput: "Run a proactive health check. Query CPU, memory, disk usage, and service status for all monitored machines. If anything looks abnormal (CPU>85%, disk>90%, memory>90%, or a key service is down), diagnose and suggest a remediation command.",
    source: 'schedule'
  }
}];

const fs = require('fs');
const path = '/home/node/.n8n/incident_memory.json';

let memory = [];
try { memory = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}

const query = (input.query || '').toLowerCase();
const results = memory.filter(m =>
  query.split(' ').some(kw => m.summary.toLowerCase().includes(kw))
);

return results.length
  ? `Found ${results.length} related incident(s):\n` + results.map(r => `â€˘ [${r.date}] ${r.summary}`).join('\n')
  : 'No similar past incidents found.';

const fs = require('fs');
const path = '/home/node/.n8n/incident_memory.json';

let memory = [];
try { memory = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}

memory.push({
  date: new Date().toISOString().slice(0, 16),
  summary: input.incident_summary
});

if (memory.length > 200) memory = memory.slice(-200);
fs.writeFileSync(path, JSON.stringify(memory, null, 2));

return `Saved. Total incidents: ${memory.length}`;
